<template>
    <div style="width: 40%; margin-left: 200px">
        <div style="margin-bottom: 30px; margin-left: 280px" >预约</div>
        <el-form :inline="true" :rules="rules" ref="ruleForm" :model="form" label-width="200px">
            <el-form-item label="图书标准码" prop="bookNo">
<!--                <el-input v-model="form.bookNo" placeholder="请输入标准码"></el-input>-->
                <el-select v-model="form.bookNo" filterable placeholder="请选择" @change="selBook">
                    <el-option
                            v-for="item in books"
                            :key="item.id"
                            :label="item.bookNo"
                            :value="item.bookNo">
                    </el-option>
                </el-select>
            </el-form-item>
            <el-form-item label="图书名称" prop="bookName">
                <el-input v-model="form.bookName" disabled ></el-input>
            </el-form-item>
          <el-form-item label="剩余数量" prop="number">
            <el-input v-model="form.number" ></el-input>
          </el-form-item>
            <el-form-item label="用户ID" prop="userId">
                <el-select v-model="form.userId" filterable placeholder="请选择" @change="selUser">
                    <el-option
                            v-for="item in users"
                            :key="item.id"
                            :label="item.name + ' ( ' + item.username + ' ) ' "
                            :value="item.id">
                    </el-option>
                </el-select>
            </el-form-item>
            <el-form-item label="用户名称" prop="userName">
                <el-input v-model="form.userName" disabled></el-input>
            </el-form-item>
            <el-form-item label="用户联系方式" prop="userPhone">
                <el-input v-model="form.userPhone" disabled></el-input>
            </el-form-item>



        </el-form>
        <div style="text-align: center; margin-top: 30px; margin-left: 20px">
            <el-button type="primary" @click="save">提交</el-button>
            <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
<!--            <el-button type="danger ">取消</el-button>-->
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";
    //导入请求
    export default {
        name: "AddAppoint",
        data(){
           return {
               form: {
               },
               books:[],
               users:[],
               rules: {
               }
           }

        },
        created() {
            request.get('/book/list').then(res => {
                this.books = res.data;
            });
            request.get('/user/list').then(res => {
                this.users = res.data;
            })

        },
        methods: {
            save() {
                this.$refs['ruleForm'].validate((valid) => {
                    if(valid){
                        request.post('/appoint/save',this.form).then(res =>{
                            if(res.code === '200'){
                                this.$notify.success('成功')
                                this.$refs['ruleForm'].resetFields();
                                this.$router.push('appointList');
                            }else{
                                this.$notify.error(res.msg)
                            }
                        })
                    }
                })

            //    对接的是后台的UserController.java文件的路径
            },
            handleChange(){

            },
            change(){
                this.$router.push('appointList');
            },
            selBook(){
             const book = this.books.find(v => v.bookNo === this.form.bookNo);
             request.get('/book/' + book.id).then(res => {
                 this.$set(this.form,'bookName',res.data.name);
                 this.$set(this.form,'number',res.data.number);
             })


            },
            selUser(){
                const user = this.users.find(v => v.id === this.form.userId);
                request.get('/user/' + user.id).then(res => {
                    this.$set(this.form,'userName',res.data.name);
                    this.$set(this.form,'userPhone',res.data.phone);
                })



            }
        }
    }
</script>

